    def load_config(self, config_file: str) -> Dict:
        try:
            with open(config_file, 'r') as f:
                return json.load(f)
        except FileNotFoundError:
            return {}

    def process_data(self, data: List[Dict]) -> List[Dict]:
        results = []
        for item in data:
